          [data-testid="shop-map-edit-mode-banner"],
          [data-testid="shop-map-resize-handle"],
          [data-testid="shop-map-yah-resize-handle"],
          [data-testid="shop-map-door-resize-handle"],
          [data-testid="shop-map-door-rotate-cw"],
